params.query:
-- Create churches table
create table churches (
  id uuid primary key default gen_random_uuid(),
  name text not null,
  admin_id uuid references auth.users(id) on delete cascade not null,
  created_at timestamptz default now() not null,
  updated_at timestamptz default now() not null
);

-- Create church_members table
create table church_members (
  id uuid primary key default gen_random_uuid(),
  church_id uuid references churches(id) on delete cascade not null,
  email text not null,
  name text,
  role text,
  created_at timestamptz default now() not null,
  unique(church_id, email)
);

-- Create services table (for scheduling)
create table services (
  id uuid primary key default gen_random_uuid(),
  church_id uuid references churches(id) on delete cascade not null,
  date timestamptz not null,
  service_type text not null,
  notes text,
  created_at timestamptz default now() not null,
  updated_at timestamptz default now() not null
);

-- Create assignments table (for service assignments)
create table assignments (
  id uuid primary key default gen_random_uuid(),
  service_id uuid references services(id) on delete cascade not null,
  member_id uuid references church_members(id) on delete cascade,
  role text not null,
  person_name text not null,
  created_at timestamptz default now() not null
);

-- Enable RLS
alter table churches enable row level security;
alter table church_members enable row level security;
alter table services enable row level security;
alter table assignments enable row level security;

-- RLS Policies for churches
create policy "Users can view churches they admin"
  on churches for select
  using (auth.uid() = admin_id);

create policy "Users can create churches"
  on churches for insert
  with check (auth.uid() = admin_id);

create policy "Users can update their own churches"
  on churches for update
  using (auth.uid() = admin_id);

create policy "Users can delete their own churches"
  on churches for delete
  using (auth.uid() = admin_id);

-- RLS Policies for church_members
create policy "Admins can view members of their churches"
  on church_members for select
  using (
    exists (
      select 1 from churches
      where churches.id = church_members.church_id
      and churches.admin_id = auth.uid()
    )
  );

create policy "Admins can add members to their churches"
  on church_members for insert
  with check (
    exists (
      select 1 from churches
      where churches.id = church_members.church_id
      and churches.admin_id = auth.uid()
    )
  );

create policy "Admins can update members in their churches"
  on church_members for update
  using (
    exists (
      select 1 from churches
      where churches.id = church_members.church_id
      and churches.admin_id = auth.uid()
    )
  );

create policy "Admins can delete members from their churches"
  on church_members for delete
  using (
    exists (
      select 1 from churches
      where churches.id = church_members.church_id
      and churches.admin_id = auth.uid()
    )
  );

-- RLS Policies for services
create policy "Admins can view services in their churches"
  on services for select
  using (
    exists (
      select 1 from churches
      where churches.id = services.church_id
      and churches.admin_id = auth.uid()
    )
  );

create policy "Admins can create services in their churches"
  on services for insert
  with check (
    exists (
      select 1 from churches
      where churches.id = services.church_id
      and churches.admin_id = auth.uid()
    )
  );

create policy "Admins can update services in their churches"
  on services for update
  using (
    exists (
      select 1 from churches
      where churches.id = services.church_id
      and churches.admin_id = auth.uid()
    )
  );

create policy "Admins can delete services in their churches"
  on services for delete
  using (
    exists (
      select 1 from churches
      where churches.id = services.church_id
      and churches.admin_id = auth.uid()
    )
  );

-- RLS Policies for assignments
create policy "Admins can view assignments in their churches"
  on assignments for select
  using (
    exists (
      select 1 from services
      join churches on churches.id = services.church_id
      where services.id = assignments.service_id
      and churches.admin_id = auth.uid()
    )
  );

create policy "Admins can create assignments in their churches"
  on assignments for insert
  with check (
    exists (
      select 1 from services
      join churches on churches.id = services.church_id
      where services.id = assignments.service_id
      and churches.admin_id = auth.uid()
    )
  );

create policy "Admins can update assignments in their churches"
  on assignments for update
  using (
    exists (
      select 1 from services
      join churches on churches.id = services.church_id
      where services.id = assignments.service_id
      and churches.admin_id = auth.uid()
    )
  );

create policy "Admins can delete assignments in their churches"
  on assignments for delete
  using (
    exists (
      select 1 from services
      join churches on churches.id = services.church_id
      where services.id = assignments.service_id
      and churches.admin_id = auth.uid()
    )
  );

-- Create recurring_services table for weekly services
CREATE TABLE IF NOT EXISTS public.recurring_services (
  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  church_id UUID NOT NULL REFERENCES public.churches(id) ON DELETE CASCADE,
  name TEXT NOT NULL,
  day_of_week INTEGER NOT NULL CHECK (day_of_week >= 0 AND day_of_week <= 6),
  time TIME NOT NULL,
  notes TEXT,
  created_at TIMESTAMPTZ DEFAULT now(),
  updated_at TIMESTAMPTZ DEFAULT now()
);

-- Create church_roles table for custom roles
CREATE TABLE IF NOT EXISTS public.church_roles (
  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  church_id UUID NOT NULL REFERENCES public.churches(id) ON DELETE CASCADE,
  name TEXT NOT NULL,
  description TEXT,
  created_at TIMESTAMPTZ DEFAULT now(),
  updated_at TIMESTAMPTZ DEFAULT now(),
  UNIQUE(church_id, name)
);

-- Enable RLS
ALTER TABLE public.recurring_services ENABLE ROW LEVEL SECURITY;
ALTER TABLE public.church_roles ENABLE ROW LEVEL SECURITY;

-- RLS Policies for recurring_services
CREATE POLICY "Users can view recurring services for their churches"
  ON public.recurring_services FOR SELECT
  USING (
    church_id IN (
      SELECT id FROM public.churches WHERE admin_id = auth.uid()
    )
  );

CREATE POLICY "Admins can insert recurring services"
  ON public.recurring_services FOR INSERT
  WITH CHECK (
    church_id IN (
      SELECT id FROM public.churches WHERE admin_id = auth.uid()
    )
  );

CREATE POLICY "Admins can update recurring services"
  ON public.recurring_services FOR UPDATE
  USING (
    church_id IN (
      SELECT id FROM public.churches WHERE admin_id = auth.uid()
    )
  );

CREATE POLICY "Admins can delete recurring services"
  ON public.recurring_services FOR DELETE
  USING (
    church_id IN (
      SELECT id FROM public.churches WHERE admin_id = auth.uid()
    )
  );

-- RLS Policies for church_roles
CREATE POLICY "Users can view roles for their churches"
  ON public.church_roles FOR SELECT
  USING (
    church_id IN (
      SELECT id FROM public.churches WHERE admin_id = auth.uid()
    )
  );

CREATE POLICY "Admins can insert roles"
  ON public.church_roles FOR INSERT
  WITH CHECK (
    church_id IN (
      SELECT id FROM public.churches WHERE admin_id = auth.uid()
    )
  );

CREATE POLICY "Admins can update roles"
  ON public.church_roles FOR UPDATE
  USING (
    church_id IN (
      SELECT id FROM public.churches WHERE admin_id = auth.uid()
    )
  );

CREATE POLICY "Admins can delete roles"
  ON public.church_roles FOR DELETE
  USING (
    church_id IN (
      SELECT id FROM public.churches WHERE admin_id = auth.uid()
    )
  );

-- Create indexes for better performance
CREATE INDEX IF NOT EXISTS idx_recurring_services_church_id ON public.recurring_services(church_id);
CREATE INDEX IF NOT EXISTS idx_church_roles_church_id ON public.church_roles(church_id);

-- Create recurring_service_roles table to link recurring services with roles
create table if not exists recurring_service_roles (
  id uuid primary key default gen_random_uuid(),
  created_at timestamp with time zone default now(),
  recurring_service_id uuid references recurring_services(id) on delete cascade not null,
  role_name text not null
);

-- Enable RLS
alter table recurring_service_roles enable row level security;

-- Create RLS policies
create policy "Users can view recurring service roles for their church"
  on recurring_service_roles for select
  using (
    exists (
      select 1 from recurring_services rs
      join churches c on rs.church_id = c.id
      where rs.id = recurring_service_roles.recurring_service_id
      and c.admin_id = auth.uid()
    )
  );

create policy "Admins can insert recurring service roles"
  on recurring_service_roles for insert
  with check (
    exists (
      select 1 from recurring_services rs
      join churches c on rs.church_id = c.id
      where rs.id = recurring_service_roles.recurring_service_id
      and c.admin_id = auth.uid()
    )
  );

create policy "Admins can delete recurring service roles"
  on recurring_service_roles for delete
  using (
    exists (
      select 1 from recurring_services rs
      join churches c on rs.church_id = c.id
      where rs.id = recurring_service_roles.recurring_service_id
      and c.admin_id = auth.uid()
    )
  );

-- Create member_unavailability table
create table if not exists public.member_unavailability (
  id uuid primary key default gen_random_uuid(),
  member_id uuid not null references public.church_members(id) on delete cascade,
  unavailable_date date not null,
  reason text,
  created_at timestamp with time zone default now(),
  updated_at timestamp with time zone default now(),
  unique(member_id, unavailable_date)
);

-- Enable RLS
alter table public.member_unavailability enable row level security;

-- Create RLS policies
create policy "Users can view their own unavailability"
  on public.member_unavailability
  for select
  using (
    member_id in (
      select id from public.church_members
      where email = auth.jwt() ->> 'email'
    )
  );

create policy "Users can insert their own unavailability"
  on public.member_unavailability
  for insert
  with check (
    member_id in (
      select id from public.church_members
      where email = auth.jwt() ->> 'email'
    )
  );

create policy "Users can delete their own unavailability"
  on public.member_unavailability
  for delete
  using (
    member_id in (
      select id from public.church_members
      where email = auth.jwt() ->> 'email'
    )
  );

-- Create index for faster queries
create index if not exists idx_member_unavailability_member_id on public.member_unavailability(member_id);
create index if not exists idx_member_unavailability_date on public.member_unavailability(unavailable_date);

-- Create member_roles junction table to support multiple roles per member
create table if not exists public.member_roles (
  id uuid primary key default gen_random_uuid(),
  member_id uuid not null references public.church_members(id) on delete cascade,
  role_id uuid not null references public.church_roles(id) on delete cascade,
  created_at timestamptz default now(),
  unique(member_id, role_id)
);

-- Enable RLS
alter table public.member_roles enable row level security;

-- RLS policies for member_roles
create policy "Users can view member roles in their churches"
  on public.member_roles for select
  using (
    exists (
      select 1 from public.church_members cm
      join public.churches c on cm.church_id = c.id
      where cm.id = member_roles.member_id
      and (c.admin_id = auth.uid() or cm.email = (select email from auth.users where id = auth.uid()))
    )
  );

create policy "Admins can insert member roles"
  on public.member_roles for insert
  with check (
    exists (
      select 1 from public.church_members cm
      join public.churches c on cm.church_id = c.id
      where cm.id = member_roles.member_id
      and c.admin_id = auth.uid()
    )
  );

create policy "Admins can delete member roles"
  on public.member_roles for delete
  using (
    exists (
      select 1 from public.church_members cm
      join public.churches c on cm.church_id = c.id
      where cm.id = member_roles.member_id
      and c.admin_id = auth.uid()
    )
  );
